class RfidFilter {
  constructor(windowMs = 2000) {
    this.windowMs = windowMs;
    this.tagMap = new Map(); // epc -> timestamp
  }

  processRead(epc) {
    const now = Date.now();
    if (this.tagMap.has(epc)) {
      const lastRead = this.tagMap.get(epc);
      if (now - lastRead < this.windowMs) {
        this.tagMap.set(epc, now); // Update window
        return null; // Suppress duplicate
      }
    }
    this.tagMap.set(epc, now);
    return epc; // Emit new tag event
  }
}

using Org.Llrp.LlrpReaderMetadata;

public class LlrpManager {
    private LLRPClient reader;

    public void ConnectReader(string ipAddress) {
        reader = new LLRPClient();
        reader.OnRoAccessReportReceived += new DelegateRoAccessReport(OnTagRead);

        bool success = reader.Connect(ipAddress, 5000);
        if (success) {
            // Send LLRP command to start reading
            reader.StartROSpec(1);
        }
    }

    private void OnTagRead(MSG_RO_ACCESS_REPORT msg) {
        foreach (var tag in msg.TagReportData) {
            string epcHex = tag.EPCParameter.ToString();
            Console.WriteLine($"Tag Spotted: {epcHex} (RSSI: {tag.PeakRSSI} dBm)");
        }
    }
}
